import { useEffect, useState } from "react";
import "./styles/Books.css";

const categoryMap = {
  Fantasy: [
    "Harry Potter",
    "The Hobbit",
    "LOTR",
    "Percy Jackson",
    "Narnia",
    "Eragon",
    "Mistborn",
    "Stormlight",
    "Witcher",
    "Good Omens",
  ],
  Business: [
    "Zero to One",
    "The Lean Startup",
    "Start With Why",
    "Good to Great",
    "Blue Ocean Strategy",
  ],
  Technology: [
    "Clean Code",
    "Design Patterns",
    "Refactoring",
    "You Don't Know JS",
  ],
  Literature: [
    "Hamlet",
    "Macbeth",
    "Pride and Prejudice",
    "Jane Eyre",
  ],
};

function HistoryByCategory() {
  const [history, setHistory] = useState({});

  useEffect(() => {
    const result = {};

    Object.keys(categoryMap).forEach((category) => {
      const borrowedBooks = categoryMap[category].filter(
        (title) => localStorage.getItem(title) === "borrowed"
      );

      result[category] = borrowedBooks;
    });

    setHistory(result);
  }, []);

  return (
    <div className="books-page">
      <h1 className="books-title">History by Category</h1>

      {Object.keys(history).map((category) => (
        <div key={category} style={{ marginBottom: "40px" }}>
          <h2 style={{ color: "#3b2416", marginBottom: "12px" }}>
            {category}
          </h2>

          {history[category].length === 0 ? (
            <p style={{ color: "#6b3f25" }}>
              No books borrowed in this category.
            </p>
          ) : (
            <ul style={{ color: "#3b2416" }}>
              {history[category].map((book, index) => (
                <li key={index}>{book}</li>
              ))}
            </ul>
          )}
        </div>
      ))}
    </div>
  );
}

export default HistoryByCategory;
